global_css:
/* Global Styles */
:root {
  --bg-color: #111214;
  --text-color: #F0F0F0;
  --accent-color: #4ADE80;
  --muted-color: #888888;
  --border-color: #333333;
  --card-bg-color: #1A1B1E;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

.page {
  width: 1242px;
  height: 1660px;
  overflow: hidden;
  background-color: var(--bg-color);
  color: var(--text-color);
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  display: flex;
  flex-direction: column;
  padding: 100px 100px;
}

.page-header {
  width: 100%;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border-color);
  margin-bottom: 60px;
}

.page-label {
  font-size: 32px;
  font-weight: 500;
  color: var(--muted-color);
  letter-spacing: 1.5px;
  text-transform: uppercase;
}

.page-title {
  font-weight: 700;
  line-height: 1.2;
  letter-spacing: -2px;
}

.page-title .accent {
  color: var(--accent-color);
}

.sub-item-list {
  list-style: none;
  margin-top: auto;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.sub-item-tag {
  font-size: 36px;
  font-weight: 600;
  color: var(--muted-color);
}

.sub-item-text {
  font-size: 42px;
  font-weight: 400;
  line-height: 1.4;
  color: var(--text-color);
}

pages.css:
.page-01 {
  padding: 0;
  justify-content: center;
}
.page-01 .content-wrapper {
  height: 100%;
  width: 100%;
  padding: 120px 100px;
  display: flex;
  flex-direction: column;
}
.page-01 .page-title {
  font-size: 160px;
  letter-spacing: -4px;
  margin-top: 20px;
  margin-bottom: auto;
}
.page-01 .divider {
  width: 100%;
  height: 1px;
  background-color: var(--border-color);
  margin-bottom: 60px;
}
.page-01 .sub-item-list {
  margin-top: 0;
  gap: 48px;
}

.page-03 .page-title {
  font-size: 140px;
  margin-bottom: 80px;
}

.page-03 .card-list {
  gap: 24px;
}

.page-03 .card-item {
  background-color: var(--card-bg-color);
  padding: 32px 40px;
  border-radius: 16px;
  border: 1px solid var(--border-color);
}

.page-03 .sub-item-tag {
  font-size: 34px;
}

.page-03 .sub-item-text {
  font-size: 40px;
}

.page-04 {
  text-align: center;
}

.page-04 .content-wrapper {
  display: flex;
  flex-direction: column;
  height: 100%;
  width: 100%;
}

.page-04 .page-title {
  font-size: 92px;
  margin-bottom: auto;
  padding-top: 40px;
}

.page-04 .metric-container {
  margin-bottom: auto;
}

.page-04 .metric-highlight {
  font-size: 150px;
  font-weight: 700;
  color: var(--accent-color);
  line-height: 1.1;
  letter-spacing: -3px;
}

.page-04 .metric-sub {
  font-size: 42px;
  font-weight: 500;
  color: var(--text-color);
  margin-top: 24px;
}

.page-04 .footnote {
  font-size: 36px;
  color: var(--muted-color);
  margin-top: auto;
  padding-bottom: 20px;
}

.page-05 .page-title {
  font-size: 108px;
  margin-bottom: 80px;
}
.page-05 .intro-item {
  margin-bottom: 80px;
}
.page-05 .intro-item .sub-item-tag {
   font-size: 36px;
   font-weight: 600;
   color: var(--muted-color);
   margin-bottom: 12px;
}
.page-05 .intro-item .sub-item-text {
  font-size: 40px;
  line-height: 1.45;
}
.page-05 .flow-steps {
  display: flex;
  flex-direction: column;
  gap: 48px;
  margin-top: auto;
}
.page-05 .flow-step {
  display: flex;
  align-items: flex-start;
  gap: 28px;
}
.page-05 .step-number {
  font-size: 40px;
  font-weight: 700;
  color: var(--muted-color);
  background-color: var(--card-bg-color);
  border: 1px solid var(--border-color);
  width: 64px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  flex-shrink: 0;
}
.page-05 .step-text {
  font-size: 42px;
  line-height: 1.4;
  padding-top: 6px;
}
.page-05 .flow-step.is-last .step-number {
  color: var(--bg-color);
  background-color: var(--accent-color);
  border-color: var(--accent-color);
}
.page-05 .flow-step.is-last .step-text {
  color: var(--accent-color);
}

.page-06 .content-wrapper {
  display: flex;
  flex-direction: column;
  height: 100%;
  width: 100%;
  text-align: center;
}
.page-06 .page-title {
  font-size: 132px;
  font-weight: 800;
  margin-top: 100px;
}
.page-06 .cta-button {
  background-color: var(--accent-color);
  color: var(--bg-color);
  border-radius: 18px;
  padding: 40px 60px;
  margin: auto 0;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 24px;
  align-self: center;
}
.page-06 .cta-icon {
  font-size: 64px;
}
.page-06 .cta-text {
  font-size: 60px;
  font-weight: 700;
}
.page-06 .sub-item-list {
  text-align: left;
  gap: 40px;
  margin-top: auto;
}
.page-06 .sub-item-text {
  font-size: 38px;
}
.page-06 .sub-item-tag {
 font-size: 34px;
}
